{
  "status": "ok",
  "version": "1.0.0",
  "uptime_seconds": 42,
  "service": "connectra",
  "diagnostics": {
    "database": true,
    "search_engine": true
  }
}

{
  "query": "query { health { apiMetadata { name version docs } apiHealth { status environment } } }"
}

{
  "data": {
    "health": {
      "apiMetadata": {
        "name": "Contact360 API",
        "version": "1.0.0",
        "docs": "/docs"
      },
      "apiHealth": {
        "status": "healthy",
        "environment": "development"
      }
    }
  }
}

type ApiMetadata {
  name: String!
  version: String!
  docs: String!
}

type ApiHealth {
  status: String!
  environment: String!
}

type ConnectraDetails {
  status: String!
  version: String
  uptime: Int
}

type VQLStats {
  message: String!
  note: String!
}

type DatabaseHealth {
  status: String!
  poolSize: Int!
  activeConnections: Int!
  idleConnections: Int!
}

type SlowEndpoint {
  endpoint: String!
  averageTimeMs: Float!
  requestCount: Int!
}

query GetApiMetadata {
  health {
    apiMetadata {
      name
      version
      docs
    }
  }
}

{
  "data": {
    "health": {
      "apiMetadata": {
        "name": "<from settings.PROJECT_NAME; often still 'Appointment GraphQL API' in config>",
        "version": "0.1.0",
        "docs": "/docs"
      }
    }
  }
}

query GetApiHealth {
  health {
    apiHealth {
      status
      environment
    }
  }
}

{
  "data": {
    "health": {
      "apiHealth": {
        "status": "healthy",
        "environment": "production"
      }
    }
  }
}

query GetVQLHealth {
  health {
    vqlHealth {
      connectraEnabled
      connectraStatus
      connectraBaseUrl
      connectraDetails {
        status
        version
        uptime
      }
      connectraError
      monitoringAvailable
    }
  }
}

{
  "data": {
    "health": {
      "vqlHealth": {
        "connectraEnabled": true,
        "connectraStatus": "healthy",
        "connectraBaseUrl": "https://connectra.example.com",
        "connectraDetails": {
          "status": "operational",
          "version": "1.0.0",
          "uptime": 86400
        },
        "connectraError": null,
        "monitoringAvailable": true
      }
    }
  }
}

query GetVQLStats {
  health {
    vqlStats {
      message
      note
    }
  }
}

query GetPerformanceStats {
  health {
    performanceStats {
      cache {
        enabled
        hits
        misses
        hitRate
      }
      slowQueries {
        thresholdMs
        countLastHour
      }
      database {
        status
        poolSize
        activeConnections
        idleConnections
      }
      s3 {
        status
        bucket
        region
      }
      endpointPerformance {
        totalRequests
        averageResponseTimeMs
        p95ResponseTimeMs
        p99ResponseTimeMs
        slowEndpoints {
          endpoint
          averageTimeMs
          requestCount
        }
      }
    }
  }
}

{
  "data": {
    "health": {
      "performanceStats": {
        "cache": {
          "enabled": true,
          "hits": 1250,
          "misses": 350,
          "hitRate": 0.78125
        },
        "slowQueries": {
          "thresholdMs": 1000,
          "countLastHour": 5
        },
        "database": {
          "status": "healthy",
          "poolSize": 20,
          "activeConnections": 8,
          "idleConnections": 12
        },
        "s3": {
          "status": "healthy",
          "bucket": "my-bucket",
          "region": "us-east-1"
        },
        "endpointPerformance": {
          "totalRequests": 10000,
          "averageResponseTimeMs": 125.5,
          "p95ResponseTimeMs": 250.0,
          "p99ResponseTimeMs": 500.0,
          "slowEndpoints": [
            {
              "endpoint": "/graphql",
              "averageTimeMs": 200.0,
              "requestCount": 100
            }
          ]
        }
      }
