}

# Get API metadata (no auth required)
query GetMetadata {
  health {
    apiMetadata {
      name
      version
      docs
    }
  }
}

# Get API health (no auth required)
query GetHealth {
  health {
    apiHealth {
      status
      environment
    }
  }
}

# Get VQL health (auth required)
query GetVQLHealth {
  health {
    vqlHealth {
      connectraEnabled
      connectraStatus
      connectraBaseUrl
      connectraDetails {
        status
        version
      }
    }
  }
}

# Get comprehensive performance stats
query GetPerformance {
  health {
    performanceStats {
      cache {
        enabled
        hits
        misses
        hitRate
        size
        maxSize
      }
      slowQueries {
        thresholdMs
        countLastHour
      }
      database {
        status
        poolSize
        activeConnections
        idleConnections
      }
      s3 {
        status
        bucket
        region
        message
      }
      endpointPerformance {
        totalRequests
        averageResponseTimeMs
        p95ResponseTimeMs
        p99ResponseTimeMs
        slowEndpoints {
          endpoint
          averageTimeMs
          requestCount
        }
      }
    }
  }
}
